import { Component, Element, Event, EventEmitter, h, Host, Method, Prop, State } from '@stencil/core';
import type { Target, TextLinkSizes, TextLinkVariants } from '../../../models/text-link.types';

@Component({
  tag: 'wdpr-breadcrumb-item',
  shadow: true,
  styles: `
    :host(.hidden) {
      display: none;
    }
    :host([data-first]) {
      --wdpr-text-link-text-display: none;
    }
    @media (min-width: 768px) {
      :host([data-first]) {
        --wdpr-text-link-text-display: inline;
      }
    }
  `,
})
export class WdprBreadcrumbItem {
  /**
   * Reference to host element
   * @type {HTMLWdprBreadcrumbItemElement}
   */
  @Element() el: HTMLWdprBreadcrumbItemElement;

  /**
   * @internal
   * Marks if the leading slot has content or not
   * @default false
   * @type {boolean}
   */
  @State() private _hasLeadingIcon: boolean = false;

  /**
   * @internal
   * Marks if the trailing slot has content or not
   * @default false
   * @type {boolean}
   */
  @State() private _hasTrailingIcon: boolean = false;

  /**
   * Flag to indicate if this breadcrumb item is the first one in the breadcrumb list.
   * @internal
   */
  @State() private _first: boolean;

  /**
   * Flag to indicate if this breadcrumb item is the last one in the breadcrumb list.
   * @internal
   */
  @State() private _last: boolean;

  /**
   * If true, shows a truncation marker (`…`) for this breadcrumb item.
   * Used internally by `WdprBreadcrumb` to collapse the item on smaller screens.
   * @internal
   * Design remove the truncation in Design 1.2.0 but not really clear how they want to handle this, we will leave it and change the logic if needed
   */
  @Prop({ reflect: true }) showTruncation: boolean = false;

  /**
   * The URL to navigate to when the item is clicked.
   * @type {string}
   */
  @Prop({ reflect: true }) href?: string;

  /**
   * The target attribute of the item. Possible values: '_blank', '_self', '_parent', '_top'.
   * @type {string}
   */
  @Prop({ reflect: true }) target?: Target = '_self';

  /**
   * If true, show a separator between this breadcrumb and the next.
   * @type {boolean}
   */
  @Prop({ reflect: true }) separator: boolean = false;

  /**
   * **Required** The text to display in the item.
   * @type {string}
   */
  @Prop({ reflect: true }) label!: string;

  /**
   * The variant of the text item.
   * @type {TextLinkVariants}
   */
  @Prop({ reflect: true }) variant?: TextLinkVariants;

  /**
   * The size of the text link. Possible values: 'xxsmall', 'xsmall', 'small', 'medium', 'large'.
   * @type {TextLinkSizes}
   */
  @Prop({ reflect: true }) size: TextLinkSizes = 'small';

  /**
   * The rel attribute of the item.
   * @type {string}
   */
  @Prop({ reflect: true }) rel?: string;

  @Event() truncationClick!: EventEmitter<void>;

  /**
   * Marks this item as the first breadcrumb in the sequence.
   * Should only be called internally by `<wdpr-breadcrumb>`.
   * @internal
   */
  @Method()
  async setFirstBreadcrumb() {
    this._first = true;
  }

  /**
   * Marks this item as the last breadcrumb in the sequence.
   * Should only be called internally by `<wdpr-breadcrumb>`.
   * @internal
   */
  @Method()
  async setLastBreadcrumb() {
    this._last = true;
  }

  componentWillLoad() {
    this._hasLeadingIcon = !!this.el.querySelector('[slot="leading-icon"]');
    this._hasTrailingIcon = !!this.el.querySelector('[slot="trailing-icon"]');
  }

  private _handleTruncationClick = () => {
    this.truncationClick.emit();
  };

  private get _isInverseVariant(): boolean {
    return this.variant?.includes('inverse') || false;
  }

  private get _separatorColorClass(): string {
    if (this._isInverseVariant) {
      return 'text-text-inverse';
    }

    return 'text-text-body';
  }

  render() {
    const { _first, _last, separator, target, label, size, showTruncation, _hasLeadingIcon, _hasTrailingIcon } = this;
    const href = this.href ?? '';
    const variant = this.variant ?? (_last ? 'secondary' : 'primary-underline');

    const attrs = { href, target, variant, size };
    const showSeparator = _last ? false : separator;
    const firstBreadcrumb = _first;

    return (
      <Host role="listitem" data-first={firstBreadcrumb ? '' : undefined}>
        <div class="flex items-center gap-100" part="wrapper">
          <span class={`${showTruncation ? 'hidden' : ''}`}>
            <wdpr-text-link {...attrs} aria-current={_last ? 'page' : undefined} rel={this.rel}>
              {_hasLeadingIcon && <slot name="leading-icon" slot="leading-icon" />}
              <span class={`${firstBreadcrumb ? 'hidden md:block' : null}`}>{label}</span>
              {_hasTrailingIcon && <slot name="trailing-icon" slot="trailing-icon" />}
            </wdpr-text-link>
          </span>

          {showTruncation && (
            <wdpr-icon-button
              variant={this._isInverseVariant ? 'inverse' : 'secondary'}
              iconName="more"
              size="small"
              a11yLabel="Show all breadcrumbs"
              onClicked={this._handleTruncationClick}
            />
          )}

          {showSeparator && (
            <span part="separator" aria-hidden="true">
              <slot name="separator">
                <wdpr-icon-library class={this._separatorColorClass} size="xsmall" icon="next" />
              </slot>
            </span>
          )}
        </div>
      </Host>
    );
  }
}
